/**
 * 弹层定位镜像 —— 修复 wujie 子应用 shadow DOM 内 popper.js / floating-ui /
 * dom-align 等定位库错位的核心模块。
 *
 * 错位根因：wujie 在 patchElementEffect 中把 element.ownerDocument 劫持成
 * iframe.document（这是 React 16- 事件委托所必须，参见 facebook/react#10422）。
 * 但定位库会顺着 el.ownerDocument.defaultView.innerWidth 这条链取视窗信息，
 * 链路终点是未代理的原生 iframe.contentWindow（默认尺寸 300x150），导致弹层
 * 位置错位。
 *
 * 修复策略 (Passive Mirror)：不动 ownerDocument 劫持，仅在 iframe.contentWindow
 * 上 defineProperty 镜像宿主 viewport 关键属性（innerWidth / scrollX /
 * visualViewport / devicePixelRatio 等 12 项）。子应用代码访问 proxyWindow
 * 走 proxy.ts 既有逻辑不变；定位库走 ownerDocument.defaultView 链下游时拿到
 * 镜像后的真实宿主 viewport。
 *
 * 镜像策略：只镜像 contentDocument.documentElement，不镜像 body / scrollingElement
 * ------------------------------------------------------------------------------
 * popper.js 0.x（element-ui v2 内置）的核心分支：
 *
 *   function getOffsetParent(element) {
 *     var offsetParent = element.offsetParent;
 *     return offsetParent === root.document.body || !offsetParent
 *       ? root.document.documentElement
 *       : offsetParent;
 *   }
 *
 * 这条分支在两种情况下进入 documentElement 路径：
 *   (a) 普通 absolute popper：popper.offsetParent === shadow body
 *       → 若 root.document.body 也是 shadow body（错误镜像），则误判，
 *         commonOffsetParent 被升级到 documentElement，错位 ~175px。
 *       → 因此 body 必须保留 wujie 原始行为（shadowRoot.body == undefined），
 *         让该判断永远 false。
 *   (b) fixed popper（el-dialog 内 select 触发）：popper.offsetParent === null
 *       → 必然返回 root.document.documentElement。此时 documentElement 必须是
 *         viewport.left == 0 的元素，否则 popper.style.left 会被错误地减去
 *         documentElement.viewport.left（在 wujie shadow 内 shadow html.viewport.left
 *         = ~225px，导致 fixed popper 整体左移 ~225px）。
 *       → 因此 documentElement 必须镜像为 hostWindow.document.documentElement
 *         （主应用 light DOM HTML 元素，viewport.left = 0）。
 *
 * scrollingElement 不镜像：popper.js 0.x 不读它，floating-ui / dom-align 在 shadow
 * 内通过 ownerDocument.scrollingElement 取滚动也是少数路径，保持原 wujie 行为
 * 风险更低；如后续库依赖此项，再单独评估。
 *
 * 综上：本模块在 contentWindow 上做 viewport 镜像（12 项），在 contentDocument 上
 * 仅镜像 documentElement 一项。
 *
 * 沙箱 destroy 时由 PopupAlignmentTracker.cleanupAll() 反向还原所有 descriptor。
 */

type RecordedDescriptor = {
  target: any;
  prop: string;
  /** 该 prop 在 patch 之前是否是 target 的 own property */
  hadOwnProperty: boolean;
  /** 原始 descriptor，可能为 undefined（原 prop 不存在）*/
  descriptor: PropertyDescriptor | undefined;
};

export class PopupAlignmentTracker {
  private readonly records: RecordedDescriptor[] = [];

  /**
   * 在 target 上 defineProperty 一个 getter，并记录原始 descriptor 以便 cleanup 还原。
   * 失败（[[Configurable]]:false 等）返回 false，不抛错，便于 patch 链路单点失败不
   * 中断后续 patch。
   */
  recordAndDefine(target: any, prop: string, getter: () => any): boolean {
    if (!target) return false;
    try {
      const hadOwnProperty = Object.prototype.hasOwnProperty.call(target, prop);
      const descriptor = Object.getOwnPropertyDescriptor(target, prop);
      Object.defineProperty(target, prop, {
        configurable: true,
        get: getter,
      });
      this.records.push({ target, prop, hadOwnProperty, descriptor });
      return true;
    } catch (_) {
      return false;
    }
  }

  /** 是否尚未 patch 过任何 descriptor。用于保活模式下避免重复 patch */
  isEmpty(): boolean {
    return this.records.length === 0;
  }

  /**
   * 反向还原所有记录的 descriptor。
   * - 原本是 own property 的：用原 descriptor restore
   * - 原本不是 own property 的：cleanup 后 delete，避免留下空 own property
   * - 任何单条还原失败都不应中断后续清理（destroy 阶段语义）
   */
  cleanupAll(): void {
    this.records.forEach(({ target, prop, hadOwnProperty, descriptor }) => {
      try {
        if (hadOwnProperty && descriptor) {
          Object.defineProperty(target, prop, descriptor);
        } else {
          delete target[prop];
        }
      } catch (_) {
        /* noop: destroy 阶段任何异常都不应中断后续清理 */
      }
    });
    this.records.length = 0;
  }
}

/**
 * patch iframe.contentWindow viewport 关键属性 + iframe.contentDocument.documentElement，
 * 让定位库 (popper.js / floating-ui / dom-align) 通过 ownerDocument 链取到的是
 * 宿主真实视窗信息，而非 iframe 自身的 300x150 默认尺寸。
 *
 * 注意：
 * - 单条属性 patch 失败不影响其他属性，失败的属性记入 failedProps 返回。
 * - getter 是动态的，每次访问都从 hostWindow 取实时值，故主窗口 resize 后
 *   弹层定位会自动跟随更新（floating-ui autoUpdate 之类的库仍可正常工作）。
 * - 调用方负责仅在 !sandbox.degrade 的场景调用本函数；degrade 模式下子应用
 *   渲染在主应用同源 iframe 内，弹层定位天然正确，无需 patch。
 * - 仅镜像 documentElement 不镜像 body / scrollingElement，避免触发 popper.js 0.x
 *   `offsetParent === root.document.body` 误判，详见模块顶部注释。
 *
 * shadowRoot 形参保留以兼容未来扩展（如基于 shadow 内 viewport 的特殊 patch），
 * 当前实现未使用，签名保留是为了避免后续再次破坏调用方。
 */
export function patchPopupAlignment(
  iframe: HTMLIFrameElement,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  _shadowRoot: ShadowRoot,
  hostWindow: Window,
  tracker: PopupAlignmentTracker
): { failedProps: string[] } {
  const failed: string[] = [];
  const cw = iframe?.contentWindow as any;
  const cd = iframe?.contentDocument as any;
  if (!cw) {
    return { failedProps: ["__no_content_window__"] };
  }

  const winMirrors: Array<[string, () => any]> = [
    ["innerWidth", () => hostWindow.innerWidth],
    ["innerHeight", () => hostWindow.innerHeight],
    ["outerWidth", () => hostWindow.outerWidth],
    ["outerHeight", () => hostWindow.outerHeight],
    ["scrollX", () => hostWindow.scrollX],
    ["scrollY", () => hostWindow.scrollY],
    ["pageXOffset", () => hostWindow.pageXOffset],
    ["pageYOffset", () => hostWindow.pageYOffset],
    ["visualViewport", () => hostWindow.visualViewport],
    ["devicePixelRatio", () => hostWindow.devicePixelRatio],
    ["getComputedStyle", () => hostWindow.getComputedStyle.bind(hostWindow)],
    ["matchMedia", () => hostWindow.matchMedia.bind(hostWindow)],
  ];
  winMirrors.forEach(([prop, getter]) => {
    if (!tracker.recordAndDefine(cw, prop, getter)) {
      failed.push(`win.${prop}`);
    }
  });

  // 仅当 contentDocument 可访问时镜像 documentElement —— 修复 popper.js 0.x
  // fixed 模式（如 el-dialog 内 select）下 commonOffsetParent 取到 shadow html
  // 导致 popper 错位 ~225px 的问题。
  if (cd) {
    if (!tracker.recordAndDefine(cd, "documentElement", () => hostWindow.document.documentElement)) {
      failed.push("doc.documentElement");
    }
  }

  return { failedProps: failed };
}

/**
 * 解析弹层定位的真实 hostWindow。
 *
 * 嵌套场景（wujie-in-wujie）：内层 wujie 通过 `window.parent` 一路向上找到第一个
 * 不是 wujie iframe 的 window，即真实浏览器顶层视窗。弹层最终绘制在浏览器顶层视窗
 * 中，定位计算应以顶层为参照系。
 *
 * 退化场景：当链路全是 wujie（异常）或已是顶层时直接返回 currentWindow。
 */
export function resolveHostWindow(currentWindow: Window): Window {
  let w: any = currentWindow;
  let depth = 0;
  // 只要 w 自己是 wujie iframe 就继续向上爬，直到 w 不再是 wujie 即真实视窗。
  // 防御 parent 链异常造成死循环（最大跨 8 层 wujie 嵌套已远超合理使用场景）。
  while (w && w.parent && w !== w.parent && (w as any).__WUJIE && depth < 8) {
    w = w.parent;
    depth++;
  }
  if (!w) return currentWindow;
  // 若停留点仍是 wujie（链路全是 wujie 异常），退化到 currentWindow
  if ((w as any).__WUJIE) return currentWindow;
  return w as Window;
}
